  1	import {
  2	  Radio,
  3	  Checkbox,
  4	  Tooltip,
  5	  TooltipPosition,
  6	  Dropdown,
  7	  DropdownList,
  8	  MenuToggleElement,
  9	  MenuToggle
 10	} from '@patternfly/react-core';
 11	import * as React from 'react';
 12	import { connect } from 'react-redux';
 13	import { KialiDispatch } from 'types/Redux';
 14	import { bindActionCreators } from 'redux';
 15	import { KialiAppState } from '../../../store/Store';
 16	import { GraphToolbarActions } from '../../../actions/GraphToolbarActions';
 17	import { TrafficRate, isAmbientRate, isGrpcRate, isHttpRate, isTcpRate } from '../../../types/Graph';
 18	import * as _ from 'lodash';
 19	import { trafficRatesSelector } from 'store/Selectors';
 20	import {
 21	  BoundingClientAwareComponent,
 22	  PropertyType
 23	} from 'components/BoundingClientAwareComponent/BoundingClientAwareComponent';
 24	import { KialiIcon } from 'config/KialiIcon';
 25	import {
 26	  containerStyle,
 27	  itemStyleWithInfo,
 28	  itemStyleWithoutInfo,
 29	  menuStyle,
 30	  menuEntryStyle
 31	} from 'styles/DropdownStyles';
 32	import { serverConfig } from 'config';
 33	import { infoStyle } from 'styles/IconStyle';
 34	
 35	type ReduxDispatchProps = {
 36	  setTrafficRates: (trafficRates: TrafficRate[]) => void;
 37	};
 38	
 39	type ReduxStateProps = {
 40	  trafficRates: TrafficRate[];
 41	};
 42	
 43	type ReduxProps = ReduxDispatchProps & ReduxStateProps;
 44	
 45	type GraphTrafficProps = ReduxProps & {
 46	  disabled: boolean;
 47	};
 48	
 49	interface TrafficRateOptionType {
 50	  disabled?: boolean;
 51	  id: string;
 52	  isChecked: boolean;
 53	  isHidden?: boolean;
 54	  labelText: string;
 55	  onChange?: () => void;
 56	  tooltip?: React.ReactNode;
 57	}
 58	
 59	const marginBottom = 20;
 60	
 61	const GraphTrafficComponent: React.FC<GraphTrafficProps> = (props: GraphTrafficProps) => {
 62	  const [isOpen, setIsOpen] = React.useState<boolean>(false);
 63	
 64	  const onToggle = (isOpen: boolean): void => {
 65	    setIsOpen(isOpen);
 66	  };
 67	
 68	  const getPopoverContent = (): React.ReactNode => {
 69	    const trafficRates = props.trafficRates;
 70	
 71	    const trafficRateOptions: TrafficRateOptionType[] = [
 72	      {
 73	        id: TrafficRate.AMBIENT_GROUP,
 74	        labelText: _.startCase(TrafficRate.AMBIENT_GROUP),
 75	        isChecked: trafficRates.includes(TrafficRate.AMBIENT_GROUP),
 76	        isHidden: !serverConfig.ambientEnabled,
 77	        tooltip: (
 78	          <div style={{ textAlign: 'left' }}>
 79	            Displays active Edges for the time period, as reported by the enabled Istio Ambient components. This is
 80	            independent of specific protocols. Default: All.
 81	          </div>
 82	        )
 83	      },
 84	      {
 85	        id: TrafficRate.GRPC_GROUP,
 86	        labelText: _.startCase(TrafficRate.GRPC_GROUP),
 87	        isChecked: trafficRates.includes(TrafficRate.GRPC_GROUP),
 88	        tooltip: (
 89	          <div style={{ textAlign: 'left' }}>
 90	            Displays active gRPC Edges for the time period, using the selected gRPC rate. To see idle gRPC Edges enable
 91	            the "Idle Edges" Display menu option. Default: Requests.
 92	          </div>
 93	        )
 94	      },
 95	      {
 96	        id: TrafficRate.HTTP_GROUP,
 97	        labelText: _.startCase(TrafficRate.HTTP_GROUP),
 98	        isChecked: trafficRates.includes(TrafficRate.HTTP_GROUP),
 99	        tooltip: (
100	          <div style={{ textAlign: 'left' }}>
101	            Displays active HTTP Edges for the time period, using the selected HTTP rate. To see idle HTTP Edges enable
102	            the "Idle Edges" Display menu option. Default: Requests.
103	          </div>
104	        )
105	      },
106	      {
107	        id: TrafficRate.TCP_GROUP,
108	        labelText: _.startCase(TrafficRate.TCP_GROUP),
109	        isChecked: trafficRates.includes(TrafficRate.TCP_GROUP),
110	        tooltip: (
111	          <div style={{ textAlign: 'left' }}>
112	            Displays active TCP Edges for the time period, using the selected TCP rate. To see inactive TCP Edges enable
113	            the "Idle Edges" Display menu option. Default: Sent Bytes.
114	          </div>
115	        )
116	      }
117	    ];
118	
119	    const ambientOptions: TrafficRateOptionType[] = [
120	      {
121	        id: TrafficRate.AMBIENT_WAYPOINT,
122	        labelText: 'Waypoint',
123	        isChecked: trafficRates.includes(TrafficRate.AMBIENT_WAYPOINT),
124	        tooltip: (
125	          <div style={{ textAlign: 'left' }}>Limit to only waypoint-reported traffic, for the enabled protocols.</div>
126	        )
127	      },
128	      {
129	        id: TrafficRate.AMBIENT_ZTUNNEL,
130	        labelText: 'Ztunnel',
131	        isChecked: trafficRates.includes(TrafficRate.AMBIENT_ZTUNNEL),
132	        tooltip: (
133	          <div style={{ textAlign: 'left' }}>
134	            Limit to only ztunnel-reported traffic. Relevant only when TCP protocol is enabled.
135	          </div>
136	        )
137	      },
138	      {
139	        id: TrafficRate.AMBIENT_TOTAL,
140	        labelText: 'Total',
141	        isChecked: trafficRates.includes(TrafficRate.AMBIENT_TOTAL),
142	        tooltip: (
143	          <div style={{ textAlign: 'left' }}>
144	            Total traffic reported by Ambient components, for the enabled protocols.
145	          </div>
146	        )
147	      }
148	    ];
149	
150	    const grpcOptions: TrafficRateOptionType[] = [
151	      {
152	        id: TrafficRate.GRPC_RECEIVED,
153	        labelText: 'Received Messages',
154	        isChecked: trafficRates.includes(TrafficRate.GRPC_RECEIVED),
155	        tooltip: (
156	          <div style={{ textAlign: 'left' }}>
157	            Received (i.e. Response) message rate in messages-per-second (mps). Captures server streaming RPCs.
158	          </div>
159	        )
160	      },
161	      {
162	        id: TrafficRate.GRPC_REQUEST,
163	        labelText: 'Requests',
164	        isChecked: trafficRates.includes(TrafficRate.GRPC_REQUEST),
165	        tooltip: (
166	          <div style={{ textAlign: 'left' }}>
167	            Request message rate in requests-per-second (rps). Captures unary RPC, with status codes.
168	          </div>
169	        )
170	      },
171	      {
172	        id: TrafficRate.GRPC_SENT,
173	        labelText: 'Sent Messages',
174	        isChecked: trafficRates.includes(TrafficRate.GRPC_SENT),
175	        tooltip: (
176	          <div style={{ textAlign: 'left' }}>
177	            Sent (i.e. Request) message rate in messages-per-second (mps). Captures client streaming RPCs.
178	          </div>
179	        )
180	      },
181	      {
182	        id: TrafficRate.GRPC_TOTAL,
183	        labelText: 'Total Messages',
184	        isChecked: trafficRates.includes(TrafficRate.GRPC_TOTAL),
185	        tooltip: (
186	          <div style={{ textAlign: 'left' }}>
187	            Combined (Sent + Received) message rate in messages-per-second (mps). Captures all streaming RPCs.
188	          </div>
189	        )
190	      }
191	    ];
192	
193	    const httpOptions: TrafficRateOptionType[] = [
194	      {
195	        id: TrafficRate.HTTP_REQUEST,
196	        labelText: 'Requests',
197	        isChecked: trafficRates.includes(TrafficRate.HTTP_REQUEST),
198	        tooltip: (
199	          <div style={{ textAlign: 'left' }}>
200	            Request message rate in requests-per-second (rps). Captures status codes.
201	          </div>
202	        )
203	      }
204	    ];
205	
206	    const tcpOptions: TrafficRateOptionType[] = [
207	      {
208	        id: TrafficRate.TCP_RECEIVED,
209	        labelText: 'Received Bytes',
210	        isChecked: trafficRates.includes(TrafficRate.TCP_RECEIVED),
211	        tooltip: <div style={{ textAlign: 'left' }}>Received bytes rate in bytes-per-second (bps).</div>
212	      },
213	      {
214	        id: TrafficRate.TCP_SENT,
215	        labelText: 'Sent Bytes',
216	        isChecked: trafficRates.includes(TrafficRate.TCP_SENT),
217	        tooltip: <div style={{ textAlign: 'left' }}>Sent bytes rate in bytes-per-second (bps).</div>
218	      },
219	      {
220	        id: TrafficRate.TCP_TOTAL,
221	        labelText: 'Total Bytes',
222	        isChecked: trafficRates.includes(TrafficRate.TCP_TOTAL),
223	        tooltip: (
224	          <div style={{ textAlign: 'left' }}>Combined (Sent + Received) byte rate in bytes-per-second (mps).</div>
225	        )
226	      }
227	    ];
228	
229	    return (
230	      <BoundingClientAwareComponent
231	        className={containerStyle}
232	        maxHeight={{ type: PropertyType.VIEWPORT_HEIGHT_MINUS_TOP, margin: marginBottom }}
233	      >
234	        <div id="graph-traffic-menu" className={menuStyle} style={{ width: '16.5em' }}>
235	          {trafficRateOptions
236	            .filter((trafficRateOption: TrafficRateOptionType) => !trafficRateOption.isHidden)
237	            .map((trafficRateOption: TrafficRateOptionType) => (
238	              <div key={trafficRateOption.id} className={menuEntryStyle}>
239	                <label
240	                  key={trafficRateOption.id}
241	                  className={trafficRateOption.tooltip ? itemStyleWithInfo : itemStyleWithoutInfo}
242	                >
243	                  <Checkbox
244	                    id={trafficRateOption.id}
245	                    name="trafficRateOptions"
246	                    isChecked={trafficRateOption.isChecked}
247	                    isDisabled={props.disabled}
248	                    label={trafficRateOption.labelText}
249	                    onChange={(event, _) => toggleTrafficRate(_, event)}
250	                    value={trafficRateOption.id}
251	                  />
252	                </label>
253	
254	                {trafficRateOption.tooltip && (
255	                  <Tooltip
256	                    key={`tooltip_${trafficRateOption.id}`}
257	                    position={TooltipPosition.right}
258	                    content={trafficRateOption.tooltip}
259	                  >
260	                    <KialiIcon.Info className={infoStyle} />
261	                  </Tooltip>
262	                )}
263	
264	                {trafficRateOption.id === TrafficRate.AMBIENT_GROUP && ambientOptions.some(o => o.isChecked) && (
265	                  <div>
266	                    {ambientOptions.map((ambientOption: TrafficRateOptionType) => (
267	                      <div key={ambientOption.id} className={menuEntryStyle}>
268	                        <label
269	                          key={ambientOption.id}
270	                          className={ambientOption.tooltip ? itemStyleWithInfo : itemStyleWithoutInfo}
271	                          style={{ paddingLeft: '2rem' }}
272	                        >
273	                          <Radio
274	                            id={ambientOption.id}
275	                            style={{ paddingLeft: '0.25rem' }}
276	                            name="ambientOptions"
277	                            isChecked={ambientOption.isChecked}
278	                            isDisabled={props.disabled}
279	                            label={ambientOption.labelText}
280	                            onChange={(event, _) => toggleTrafficRateAmbient(_, event)}
281	                            value={ambientOption.id}
282	                          />
283	                        </label>
284	                        {ambientOption.tooltip && (
285	                          <Tooltip
286	                            key={`tooltip_${ambientOption.id}`}
287	                            position={TooltipPosition.right}
288	                            content={ambientOption.tooltip}
289	                          >
290	                            <KialiIcon.Info className={infoStyle} />
291	                          </Tooltip>
292	                        )}
293	                      </div>
294	                    ))}
295	                  </div>
296	                )}
297	
298	                {trafficRateOption.id === TrafficRate.GRPC_GROUP && grpcOptions.some(o => o.isChecked) && (
299	                  <div>
300	                    {grpcOptions.map((grpcOption: TrafficRateOptionType) => (
301	                      <div key={grpcOption.id} className={menuEntryStyle}>
302	                        <label
303	                          key={grpcOption.id}
304	                          className={grpcOption.tooltip ? itemStyleWithInfo : itemStyleWithoutInfo}
305	                          style={{ paddingLeft: '2rem' }}
306	                        >
307	                          <Radio
308	                            id={grpcOption.id}
309	                            style={{ paddingLeft: '0.25rem' }}
310	                            name="grpcOptions"
311	                            isChecked={grpcOption.isChecked}
312	                            isDisabled={props.disabled}
313	                            label={grpcOption.labelText}
314	                            onChange={(event, _) => toggleTrafficRateGrpc(_, event)}
315	                            value={grpcOption.id}
316	                          />
317	                        </label>
318	                        {grpcOption.tooltip && (
319	                          <Tooltip
320	                            key={`tooltip_${grpcOption.id}`}
321	                            position={TooltipPosition.right}
322	                            content={grpcOption.tooltip}
323	                          >
324	                            <KialiIcon.Info className={infoStyle} />
325	                          </Tooltip>
326	                        )}
327	                      </div>
328	                    ))}
329	                  </div>
330	                )}
331	
332	                {trafficRateOption.id === TrafficRate.HTTP_GROUP && httpOptions.some(o => o.isChecked) && (
333	                  <div>
334	                    {httpOptions.map((httpOption: TrafficRateOptionType) => (
335	                      <div key={httpOption.id} className={menuEntryStyle}>
336	                        <label
337	                          key={httpOption.id}
338	                          className={httpOption.tooltip ? itemStyleWithInfo : itemStyleWithoutInfo}
339	                          style={{ paddingLeft: '2rem' }}
340	                        >
341	                          <Radio
342	                            id={httpOption.id}
343	                            style={{ paddingLeft: '0.25rem' }}
344	                            name="httpOptions"
345	                            isChecked={httpOption.isChecked}
346	                            isDisabled={props.disabled}
347	                            label={httpOption.labelText}
348	                            onChange={(event, _) => toggleTrafficRateHttp(_, event)}
349	                            value={httpOption.id}
350	                          />
351	                        </label>
352	
353	                        {httpOption.tooltip && (
354	                          <Tooltip
355	                            key={`tooltip_${httpOption.id}`}
356	                            position={TooltipPosition.right}
357	                            content={httpOption.tooltip}
358	                          >
359	                            <KialiIcon.Info className={infoStyle} />
360	                          </Tooltip>
361	                        )}
362	                      </div>
363	                    ))}
364	                  </div>
365	                )}
366	
367	                {trafficRateOption.id === TrafficRate.TCP_GROUP && tcpOptions.some(o => o.isChecked) && (
368	                  <div>
369	                    {tcpOptions.map((tcpOption: TrafficRateOptionType) => (
370	                      <div key={tcpOption.id} className={menuEntryStyle}>
371	                        <label
372	                          key={tcpOption.id}
373	                          className={tcpOption.tooltip ? itemStyleWithInfo : itemStyleWithoutInfo}
374	                          style={{ paddingLeft: '2rem' }}
375	                        >
376	                          <Radio
377	                            id={tcpOption.id}
378	                            style={{ paddingLeft: '0.25rem' }}
379	                            name="tcpOptions"
380	                            isChecked={tcpOption.isChecked}
381	                            isDisabled={props.disabled}
382	                            label={tcpOption.labelText}
383	                            onChange={(event, _) => toggleTrafficRateTcp(_, event)}
384	                            value={tcpOption.id}
385	                          />
386	                        </label>
387	                        {tcpOption.tooltip && (
388	                          <Tooltip
389	                            key={`tooltip_${tcpOption.id}`}
390	                            position={TooltipPosition.right}
391	                            content={tcpOption.tooltip}
392	                          >
393	                            <KialiIcon.Info className={infoStyle} />
394	                          </Tooltip>
395	                        )}
396	                      </div>
397	                    ))}
398	                  </div>
399	                )}
400	              </div>
401	            ))}
402	        </div>
403	      </BoundingClientAwareComponent>
404	    );
405	  };
406	
407	  const toggleTrafficRate = (_, event): void => {
408	    const rate = event.target.value as TrafficRate;
409	
410	    if (props.trafficRates.includes(rate)) {
411	      let newRates: TrafficRate[];
412	
413	      switch (rate) {
414	        case TrafficRate.AMBIENT_GROUP:
415	          newRates = props.trafficRates.filter(r => !isAmbientRate(r));
416	          break;
417	        case TrafficRate.GRPC_GROUP:
418	          newRates = props.trafficRates.filter(r => !isGrpcRate(r));
419	          break;
420	        case TrafficRate.HTTP_GROUP:
421	          newRates = props.trafficRates.filter(r => !isHttpRate(r));
422	          break;
423	        case TrafficRate.TCP_GROUP:
424	          newRates = props.trafficRates.filter(r => !isTcpRate(r));
425	          break;
426	        default:
427	          newRates = props.trafficRates.filter(r => r !== rate);
428	      }
429	
430	      props.setTrafficRates(newRates);
431	    } else {
432	      switch (rate) {
433	        case TrafficRate.AMBIENT_GROUP:
434	          props.setTrafficRates([...props.trafficRates, rate, TrafficRate.AMBIENT_TOTAL]);
435	          break;
436	        case TrafficRate.GRPC_GROUP:
437	          props.setTrafficRates([...props.trafficRates, rate, TrafficRate.GRPC_REQUEST]);
438	          break;
439	        case TrafficRate.HTTP_GROUP:
440	          props.setTrafficRates([...props.trafficRates, rate, TrafficRate.HTTP_REQUEST]);
441	          break;
442	        case TrafficRate.TCP_GROUP:
443	          props.setTrafficRates([...props.trafficRates, rate, TrafficRate.TCP_SENT]);
444	          break;
445	        default:
446	          props.setTrafficRates([...props.trafficRates, rate]);
447	      }
448	    }
449	  };
450	
451	  const toggleTrafficRateAmbient = (_, event): void => {
452	    const rate = event.target.value as TrafficRate;
453	    const newRates = props.trafficRates.filter(r => !isAmbientRate(r));
454	    props.setTrafficRates([...newRates, TrafficRate.AMBIENT_GROUP, rate]);
455	  };
456	
457	  const toggleTrafficRateGrpc = (_, event): void => {
458	    const rate = event.target.value as TrafficRate;
459	    const newRates = props.trafficRates.filter(r => !isGrpcRate(r));
460	    props.setTrafficRates([...newRates, TrafficRate.GRPC_GROUP, rate]);
461	  };
462	
463	  const toggleTrafficRateHttp = (_, event): void => {
464	    const rate = event.target.value as TrafficRate;
465	    const newRates = props.trafficRates.filter(r => !isHttpRate(r));
466	    props.setTrafficRates([...newRates, TrafficRate.HTTP_GROUP, rate]);
467	  };
468	
469	  const toggleTrafficRateTcp = (_, event): void => {
470	    const rate = event.target.value as TrafficRate;
471	    const newRates = props.trafficRates.filter(r => !isTcpRate(r));
472	    props.setTrafficRates([...newRates, TrafficRate.TCP_GROUP, rate]);
473	  };
474	
475	  return (
476	    <Dropdown
477	      toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
478	        <MenuToggle
479	          ref={toggleRef}
480	          id="graph-traffic-dropdown"
481	          isDisabled={props.disabled}
482	          onClick={() => onToggle(!isOpen)}
483	          isExpanded={isOpen}
484	        >
485	          Traffic
486	        </MenuToggle>
487	      )}
488	      isOpen={isOpen}
489	      onOpenChange={(isOpen: boolean) => onToggle(isOpen)}
490	    >
491	      <DropdownList>{getPopoverContent()}</DropdownList>
492	    </Dropdown>
493	  );
494	};
495	
496	// Allow Redux to map sections of our global app state to our props
497	const mapStateToProps = (state: KialiAppState): ReduxStateProps => ({
498	  trafficRates: trafficRatesSelector(state)
499	});
500	
501	// Map our actions to Redux
502	const mapDispatchToProps = (dispatch: KialiDispatch): ReduxDispatchProps => {
503	  return {
504	    setTrafficRates: bindActionCreators(GraphToolbarActions.setTrafficRates, dispatch)
505	  };
506	};
507	
508	// hook up to Redux for our State to be mapped to props
509	export const GraphTraffic = connect(mapStateToProps, mapDispatchToProps)(GraphTrafficComponent);

